const data = $input.first().json;
const docs = data.result || [];
const todasLasCategorias = data.existing_categories || ['Sin clasificar'];

if (docs.length === 0) {
  return [{ json: { error: 'No hay documentos' } }];
}

// Filtrar: quitar categorías que son títulos largos o frases (>4 palabras)
// Solo dejar las que parecen nombres de categoría reales
const categorias = todasLasCategorias.filter(cat => {
  const palabras = cat.trim().split(/\s+/);
  return palabras.length <= 4 && cat.length <= 40;
});

// Asegurar que "Sin clasificar" siempre esté
if (!categorias.includes('Sin clasificar')) {
  categorias.push('Sin clasificar');
}

// Formatear documentos para el prompt
let listaDocs = '';
for (const doc of docs) {
  const tags = doc.metadata?.tags || [];
  const preview = (doc.text || '').slice(0, 400);
  listaDocs += `\nID: ${doc.id}\nArchivo: ${doc.metadata?.filename || doc.id}\nEtiquetas: ${tags.join(', ') || 'ninguna'}\nTexto: ${preview}\n---`;
}

const prompt = `Eres un asistente que categoriza documentos. Tu tarea es analizar cada documento y asignarle la categoría más apropiada.

CATEGORÍAS DISPONIBLES (usa EXACTAMENTE estos nombres):
${categorias.join('\n')}

REGLAS:
- Analiza las etiquetas y el texto del documento
- Elige la categoría que mejor describa el tema principal del documento
- Si ninguna categoría encaja claramente, usa: Sin clasificar
- NO inventes categorías nuevas, solo usa las de la lista de arriba

DOCUMENTOS:
${listaDocs}

Responde ÚNICAMENTE con un array JSON válido, sin texto extra, sin explicaciones, sin bloques de código:
[
  {"id": "id_documento", "category": "NombreCategoria", "reason": "motivo breve"},
  ...
]`;

return [{ json: { prompt, total: docs.length, categorias_disponibles: categorias } }];

// Parsear respuesta de Qwen
const raw = $input.first().json.response || '';

let decisiones = [];

try {
  // Qwen a veces envuelve el JSON en texto o en bloques ```json
  // Buscar el array JSON dentro de la respuesta
  const match = raw.match(/\[\s*\{[\s\S]*?\}\s*\]/);
  if (match) {
    decisiones = JSON.parse(match[0]);
  } else {
    decisiones = JSON.parse(raw.trim());
  }
} catch (e) {
  // Si falla el parseo, loguear y retornar error
  return [{ json: { error: 'No se pudo parsear respuesta de Qwen', raw: raw.slice(0, 300) } }];
}

// Filtrar entradas inválidas
const validas = decisiones.filter(d => d.id && d.category);

console.log(`Qwen categorizó ${validas.length} documentos`);

// Devolver uno por uno para que el siguiente nodo itere sobre cada uno
return validas.map(d => ({ json: d }));
